export interface Product {
  id: string;
  name: string;
  price: number;
  category: string;
  imageUrl?: string;
  description?: string; // For the tooltip
}

export interface CartItem extends Product {
  quantity: number;
}

export type Category = 'All' | 'Coffee' | 'Bakery' | 'Dessert';

import { initializeApp } from "firebase/app";
import { getAuth, GoogleAuthProvider } from "firebase/auth";
import { getFirestore } from "firebase/firestore";

const firebaseConfig = {
  apiKey: "AIzaSyC6pnhMDA1-en0sycZt81oDXbd4lTc748Y",
  authDomain: "jeeranan-khampuak.firebaseapp.com",
  projectId: "jeeranan-khampuak",
  storageBucket: "jeeranan-khampuak.firebasestorage.app",
  messagingSenderId: "445601401901",
  appId: "1:445601401901:web:d708606e20599999293ca4",
  measurementId: "G-834YJ1D66H"
};

const app = initializeApp(firebaseConfig);
export const auth = getAuth(app);
export const googleProvider = new GoogleAuthProvider();
export const db = getFirestore(app);

import { collection, getDocs, query } from "firebase/firestore";
import { db } from "../firebaseConfig";
import { Product } from "../types";

export const getProducts = async (): Promise<Product[]> => {
  try {
    const q = query(collection(db, "cafe"));
    const querySnapshot = await getDocs(q);

    // Check if empty, if so, return some mock data for visualization if the DB is empty
    if (querySnapshot.empty) {
        console.warn("Firestore collection 'cafe' is empty. Returning mock data.");
        return [
            { id: '1', name: 'ครีมมี เพียวมัทฉะ ลาเต้', price: 150, category: 'Coffee', imageUrl: 'https://picsum.photos/200/200?random=1', description: 'สูตรเข้มข้น ตาตื่น 100%' },
            { id: '2', name: 'คลาสสิค ช็อกโกแลต', price: 125, category: 'Coffee', imageUrl: 'https://picsum.photos/200/200?random=2', description: 'สูตรเข้มข้น 100%' },
            { id: '3', name: 'ครัวซองต์เนยสด', price: 85, category: 'Bakery', imageUrl: 'https://picsum.photos/200/200?random=3', description: 'หอมเนยฝรั่งเศส' },
            { id: '4', name: 'เค้กส้ม', price: 95, category: 'Dessert', imageUrl: 'https://picsum.photos/200/200?random=4', description: 'เปรี้ยวหวานลงตัว' },
        ];
    }

    const products: Product[] = [];
    querySnapshot.forEach((doc) => {
      const data = doc.data();
      products.push({
        id: doc.id,
        name: data.name || "Unknown Item",
        price: Number(data.price) || 0,
        category: data.category || "General",
        imageUrl: data.image || data.imageUrl || "https://picsum.photos/200/300",
        description: data.description || ""
      });
    });
    return products;
  } catch (error) {
    console.error("Error fetching products: ", error);
    throw error;
  }
};

import React, { useState } from 'react';
import { signInWithPopup, signInWithEmailAndPassword } from "firebase/auth";
import { auth, googleProvider } from "../firebaseConfig";
import { Coffee, Lock, Mail, LogIn } from 'lucide-react';

const LoginPage: React.FC = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleGoogleLogin = async () => {
    try {
      setLoading(true);
      await signInWithPopup(auth, googleProvider);
    } catch (err: any) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const handleEmailLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setLoading(true);
    try {
      await signInWithEmailAndPassword(auth, email, password);
    } catch (err: any) {
      setError("Login failed: " + err.message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-gray-100 flex flex-col justify-center py-12 sm:px-6 lg:px-8">
      <div className="sm:mx-auto sm:w-full sm:max-w-md">
        <div className="flex justify-center">
            <div className="bg-orange-500 p-3 rounded-full">
                <Coffee className="h-10 w-10 text-white" />
            </div>
        </div>
        <h2 className="mt-6 text-center text-3xl font-extrabold text-gray-900">
          Cafe POS System
        </h2>
        <p className="mt-2 text-center text-sm text-gray-600">
          Please sign in to continue
        </p>
      </div>

      <div className="mt-8 sm:mx-auto sm:w-full sm:max-w-md">
        <div className="bg-white py-8 px-4 shadow sm:rounded-lg sm:px-10">
          <form className="space-y-6" onSubmit={handleEmailLogin}>
            <div>
              <label htmlFor="email" className="block text-sm font-medium text-gray-700">
                Email address
              </label>
              <div className="mt-1 relative rounded-md shadow-sm">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                  <Mail className="h-5 w-5 text-gray-400" />
                </div>
                <input
                  id="email"
                  name="email"
                  type="email"
                  autoComplete="email"
                  required
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  className="focus:ring-orange-500 focus:border-orange-500 block w-full pl-10 sm:text-sm border-gray-300 rounded-md p-2 border"
                  placeholder="you@example.com"
                />
              </div>
            </div>

            <div>
              <label htmlFor="password" className="block text-sm font-medium text-gray-700">
                Password
              </label>
              <div className="mt-1 relative rounded-md shadow-sm">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                  <Lock className="h-5 w-5 text-gray-400" />
                </div>
                <input
                  id="password"
                  name="password"
                  type="password"
                  autoComplete="current-password"
                  required
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  className="focus:ring-orange-500 focus:border-orange-500 block w-full pl-10 sm:text-sm border-gray-300 rounded-md p-2 border"
                  placeholder="********"
                />
              </div>
            </div>

            {error && <div className="text-red-600 text-sm text-center">{error}</div>}

            <div>
              <button
                type="submit"
                disabled={loading}
                className="w-full flex justify-center py-2 px-4 border border-transparent rounded-md shadow-sm text-sm font-medium text-white bg-orange-600 hover:bg-orange-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-orange-500 disabled:opacity-50"
              >
                 {loading ? 'Signing in...' : 'Sign in with Email'}
              </button>
            </div>
          </form>

          <div className="mt-6">
            <div className="relative">
              <div className="absolute inset-0 flex items-center">
                <div className="w-full border-t border-gray-300" />
              </div>
              <div className="relative flex justify-center text-sm">
                <span className="px-2 bg-white text-gray-500">Or continue with</span>
              </div>
            </div>

            <div className="mt-6">
              <button
                onClick={handleGoogleLogin}
                disabled={loading}
                className="w-full flex justify-center items-center px-4 py-2 border border-gray-300 shadow-sm text-sm font-medium rounded-md text-gray-700 bg-white hover:bg-gray-50 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-orange-500"
              >
               <svg className="h-5 w-5 mr-2" viewBox="0 0 24 24">
                  <path
                    fill="#4285F4"
                    d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z"
                  />
                  <path
                    fill="#34A853"
                    d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z"
                  />
                  <path
                    fill="#FBBC05"
                    d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z"
                  />
                  <path
                    fill="#EA4335"
                    d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z"
                  />
                </svg>
                Sign in with Google
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default LoginPage;

import React from 'react';
import { Product } from '../types';

interface ProductCardProps {
  product: Product;
  onClick: (product: Product) => void;
  onImageClick: (imgUrl: string) => void;
}

const ProductCard: React.FC<ProductCardProps> = ({ product, onClick, onImageClick }) => {
  return (
    <div 
      className="group bg-white rounded-xl shadow-md overflow-hidden transform transition duration-300 hover:-translate-y-2 hover:shadow-2xl border border-transparent hover:border-orange-200 cursor-pointer h-full flex flex-col"
      onClick={() => onClick(product)}
    >
      <div className="relative overflow-hidden h-48">
        <img 
          src={product.imageUrl} 
          alt={product.name} 
          className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-110"
          onClick={(e) => {
            e.stopPropagation();
            if(product.imageUrl) onImageClick(product.imageUrl);
          }}
        />
        {/* Tooltip implementation matching design */}
        {product.description && (
          <div className="absolute bottom-0 left-1/2 transform -translate-x-1/2 translate-y-full group-hover:-translate-y-12 transition-transform duration-300 z-10">
             <div className="bg-gray-800 text-white text-xs px-3 py-1 rounded shadow-lg whitespace-nowrap opacity-0 group-hover:opacity-100 transition-opacity delay-100">
                {product.description}
             </div>
          </div>
        )}
      </div>
      <div className="p-4 flex flex-col flex-grow justify-between text-center">
        <h5 className="text-lg font-semibold text-gray-800 mb-2">{product.name}</h5>
        <p className="text-xl font-bold text-orange-600">{product.price.toLocaleString()} บาท</p>
      </div>
    </div>
  );
};

export default ProductCard;

import React, { useEffect, useState } from 'react';
import { signOut } from "firebase/auth";
import { auth } from "../firebaseConfig";
import { getProducts } from '../services/posService';
import { Product, CartItem, Category } from '../types';
import ProductCard from './ProductCard';
import { LogOut, RefreshCcw, Coffee, Cake, IceCream, Utensils, X, Plus, Minus, Trash2 } from 'lucide-react';

const POSLayout: React.FC = () => {
  const [products, setProducts] = useState<Product[]>([]);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [loading, setLoading] = useState(true);
  const [activeCategory, setActiveCategory] = useState<Category>('All');
  const [lightboxImg, setLightboxImg] = useState<string | null>(null);

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    setLoading(true);
    try {
      const data = await getProducts();
      setProducts(data);
    } catch (error) {
      console.error("Failed to load products");
    } finally {
      setLoading(false);
    }
  };

  const handleLogout = () => {
    signOut(auth);
  };

  const addToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        return prev.map(item => 
          item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item
        );
      }
      return [...prev, { ...product, quantity: 1 }];
    });
  };

  const removeFromCart = (productId: string) => {
    setCart(prev => prev.filter(item => item.id !== productId));
  };

  const updateQuantity = (productId: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === productId) {
        const newQty = item.quantity + delta;
        return newQty > 0 ? { ...item, quantity: newQty } : item;
      }
      return item;
    }));
  };

  const clearCart = () => setCart([]);

  const totalAmount = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);

  const filteredProducts = activeCategory === 'All' 
    ? products 
    : products.filter(p => p.category === activeCategory || (activeCategory === 'Coffee' && !p.category)); // Fallback for simple data

  const categories: {id: Category, label: string, icon: React.ReactNode}[] = [
    { id: 'All', label: 'ทั้งหมด', icon: <Utensils size={18} /> },
    { id: 'Coffee', label: 'กาแฟ', icon: <Coffee size={18} /> },
    { id: 'Bakery', label: 'เบเกอรี่', icon: <Cake size={18} /> },
    { id: 'Dessert', label: 'ของหวาน', icon: <IceCream size={18} /> },
  ];

  return (
    <div className="flex flex-col h-screen overflow-hidden bg-gray-50">
      {/* Header */}
      <header className="bg-white shadow-sm h-16 flex items-center justify-between px-6 z-20">
        <h1 className="text-xl font-bold text-gray-800 flex items-center gap-2">
           <Coffee className="text-orange-500" />
           Cafe POS
        </h1>
        <button 
          onClick={handleLogout} 
          className="flex items-center gap-2 text-gray-600 hover:text-red-500 transition-colors"
        >
          <LogOut size={20} />
          <span>ออกจากระบบ</span>
        </button>
      </header>

      {/* Main Content */}
      <div className="flex flex-1 overflow-hidden">
        {/* Left Side: Product Selection */}
        <div className="w-full md:w-2/3 lg:w-3/4 flex flex-col bg-gray-100 border-r border-gray-200">

          {/* Category Tabs */}
          <div className="p-4 bg-white shadow-sm overflow-x-auto whitespace-nowrap">
            <h2 className="text-lg font-bold mb-3 text-gray-700">โซนเลือกสินค้า</h2>
            <div className="flex space-x-2">
              {categories.map(cat => (
                <button
                  key={cat.id}
                  onClick={() => setActiveCategory(cat.id)}
                  className={`flex items-center gap-2 px-6 py-2.5 rounded-full text-sm font-medium transition-all duration-200 ${
                    activeCategory === cat.id 
                    ? 'bg-orange-500 text-white shadow-md transform scale-105' 
                    : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
                  }`}
                >
                  {cat.icon}
                  {cat.label}
                </button>
              ))}
            </div>
          </div>

          {/* Product Grid */}
          <div className="flex-1 overflow-y-auto p-4 md:p-6">
            {loading ? (
              <div className="flex justify-center items-center h-full text-gray-400">
                <RefreshCcw className="animate-spin mr-2" /> Loading Products...
              </div>
            ) : (
              <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-4 md:gap-6">
                {filteredProducts.map(product => (
                  <ProductCard 
                    key={product.id} 
                    product={product} 
                    onClick={addToCart}
                    onImageClick={setLightboxImg}
                  />
                ))}
              </div>
            )}
          </div>
        </div>

        {/* Right Side: Cart & Checkout */}
        <div className="w-full md:w-1/3 lg:w-1/4 bg-white flex flex-col shadow-xl h-full z-10">
          <div className="p-4 bg-orange-50 border-b border-orange-100">
             <h2 className="text-xl font-bold text-gray-800">โซนจ่ายเงิน</h2>
          </div>

          {/* Cart Items List */}
          <div className="flex-1 overflow-y-auto p-4 space-y-3">
             {cart.length === 0 ? (
               <div className="h-full flex flex-col items-center justify-center text-gray-400 opacity-50">
                  <Utensils size={48} className="mb-2" />
                  <p>ยังไม่มีรายการสินค้า</p>
               </div>
             ) : (
               <table className="w-full text-sm">
                 <thead className="text-gray-500 border-b">
                   <tr>
                     <th className="text-left pb-2 font-normal">รายการ</th>
                     <th className="text-right pb-2 font-normal">ราคา</th>
                   </tr>
                 </thead>
                 <tbody className="divide-y">
                   {cart.map((item) => (
                     <tr key={item.id} className="group">
                       <td className="py-3 pr-2">
                         <div className="font-medium text-gray-800">{item.name}</div>
                         <div className="flex items-center mt-1 space-x-2">
                            <button 
                                onClick={() => updateQuantity(item.id, -1)}
                                className="p-1 bg-gray-200 rounded hover:bg-gray-300 text-gray-600"
                            >
                                <Minus size={12} />
                            </button>
                            <span className="font-bold w-6 text-center">{item.quantity}</span>
                            <button 
                                onClick={() => updateQuantity(item.id, 1)}
                                className="p-1 bg-gray-200 rounded hover:bg-gray-300 text-gray-600"
                            >
                                <Plus size={12} />
                            </button>
                            <button 
                              onClick={() => removeFromCart(item.id)}
                              className="ml-auto text-red-400 hover:text-red-600 p-1 opacity-0 group-hover:opacity-100 transition-opacity"
                            >
                              <Trash2 size={14} />
                            </button>
                         </div>
                       </td>
                       <td className="text-right align-top py-3 font-semibold text-gray-700">
                         {(item.price * item.quantity).toLocaleString()}
                       </td>
                     </tr>
                   ))}
                 </tbody>
               </table>
             )}
          </div>

          {/* Summary & Actions */}
          <div className="bg-gray-50 p-4 border-t border-gray-200 shadow-inner">
             <div className="flex justify-between items-end mb-4 border-b border-gray-200 pb-4">
                <span className="text-lg font-medium text-gray-600">ยอดรวมสุทธิ</span>
                <span className="text-3xl font-bold text-red-600">{totalAmount.toLocaleString(undefined, { minimumFractionDigits: 2 })}</span>
             </div>

             <div className="grid grid-cols-2 gap-3 mb-3">
                <button className="bg-yellow-400 hover:bg-yellow-500 text-yellow-900 font-semibold py-3 rounded-lg transition-colors">
                  พักบิล
                </button>
                <button 
                  onClick={clearCart}
                  className="bg-white border border-red-500 text-red-500 hover:bg-red-50 font-semibold py-3 rounded-lg transition-colors"
                >
                  ยกเลิก
                </button>
             </div>
             <button className="w-full bg-green-500 hover:bg-green-600 text-white font-bold text-xl py-4 rounded-xl shadow-lg hover:shadow-green-500/30 transition-all transform active:scale-95">
               ชำระเงิน (Charge)
             </button>
          </div>
        </div>
      </div>

      {/* Lightbox Modal */}
      {lightboxImg && (
        <div 
          className="fixed inset-0 z-50 flex items-center justify-center bg-black bg-opacity-90 backdrop-blur-sm animate-fade-in"
          onClick={() => setLightboxImg(null)}
        >
            <button 
                className="absolute top-5 right-5 text-white hover:text-gray-300 transition-colors"
                onClick={() => setLightboxImg(null)}
            >
                <X size={40} />
            </button>
            <img 
                src={lightboxImg} 
                alt="Enlarged" 
                className="max-w-[90%] max-h-[90%] rounded-lg shadow-2xl transform transition-transform duration-300 scale-100"
                onClick={(e) => e.stopPropagation()} 
            />
        </div>
      )}
    </div>
  );
};

export default POSLayout;

import React, { useEffect, useState } from 'react';
import { onAuthStateChanged, User } from "firebase/auth";
import { auth } from "./firebaseConfig";
import LoginPage from './components/LoginPage';
import POSLayout from './components/POSLayout';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, (currentUser) => {
      setUser(currentUser);
      setLoading(false);
    });

    return () => unsubscribe();
  }, []);

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-100">
         <div className="animate-spin rounded-full h-16 w-16 border-t-2 border-b-2 border-orange-500"></div>
      </div>
    );
  }

  return (
    <>
      {user ? <POSLayout /> : <LoginPage />}
    </>
  );
};

export default App;

