export const getProducts = async (): Promise<Product[]> => {
  try {
    const q = query(collection(db, "cafe"));
    const querySnapshot = await getDocs(q);

    // Check if empty, if so, return some mock data for visualization if the DB is empty
    if (querySnapshot.empty) {
        console.warn("Firestore collection 'cafe' is empty. Returning mock data.");
        return MOCK_PRODUCTS;
    }

    const products: Product[] = [];
    querySnapshot.forEach((doc) => {
      const data = doc.data();
      products.push({
        id: doc.id,
        name: data.name || "Unknown Item",
        price: Number(data.price) || 0,
        category: data.category || "General",
        imageUrl: data.image || data.imageUrl || "https://placehold.co/200x200?text=No+Image",
        description: data.description || ""
      });
    });
    return products;
  } catch (error: any) {
    console.error("Error fetching products from Firestore: ", error);

    // Fallback to mock data on permission error or other failures to ensure the app is usable
    // This handles the 'Missing or insufficient permissions' error common when security rules aren't set up
    if (error.code === 'permission-denied' || error.message?.includes('permission') || error.message?.includes('Missing or insufficient permissions')) {
        console.warn("Using mock data due to missing Firestore permissions.");
        return MOCK_PRODUCTS;
    }

    // Return mock data for any other error as well to keep the UI functional
    return MOCK_PRODUCTS;
  }
};

