                    <label className="block text-sm font-medium text-gray-700">ชื่อสินค้า (Title)</label>
                    <input 
                        type="text" 
                        required
                        value={formData.name}
                        onChange={e => setFormData({...formData, name: e.target.value})}
                        className="mt-1 block w-full rounded-md border-gray-300 shadow-sm focus:border-green-500 focus:ring-green-500 border p-2"
                    />
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-gray-700">หมวดหมู่</label>
                    <select 
                        value={formData.category}
                        onChange={e => setFormData({...formData, category: e.target.value as Category})}
                        className="mt-1 block w-full rounded-md border-gray-300 shadow-sm focus:border-green-500 focus:ring-green-500 border p-2"
                    >
                        <option value="Coffee">กาแฟ (Coffee)</option>
                        <option value="Bakery">เบเกอรี่ (Bakery)</option>
                        <option value="Dessert">ของหวาน (Dessert)</option>
                    </select>
                  </div>
               </div>

               <div className="grid grid-cols-3 gap-4">
                  <div>
                    <label className="block text-sm font-medium text-gray-700">ราคา (Price)</label>
                    <input 
                        type="number" 
                        required
                        min="0"
                        value={formData.price}
                        onChange={e => setFormData({...formData, price: Number(e.target.value)})}
                        className="mt-1 block w-full rounded-md border-gray-300 shadow-sm focus:border-green-500 focus:ring-green-500 border p-2"
                    />
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-gray-700">หน่วย (Unit)</label>
                    <input 
                        type="text" 
                        value={formData.unit}
                        onChange={e => setFormData({...formData, unit: e.target.value})}
                        className="mt-1 block w-full rounded-md border-gray-300 shadow-sm focus:border-green-500 focus:ring-green-500 border p-2"
                        placeholder="แก้ว, ชิ้น"
                    />
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-gray-700">สถานะ</label>
                    <select 
                        value={formData.status}
                        onChange={e => setFormData({...formData, status: e.target.value as any})}
                        className="mt-1 block w-full rounded-md border-gray-300 shadow-sm focus:border-green-500 focus:ring-green-500 border p-2"
                    >
                        <option value="In Stock">In Stock</option>
                        <option value="Sold Out">Sold Out</option>
                    </select>
                  </div>
               </div>

               <div>
                    <label className="block text-sm font-medium text-gray-700">รายละเอียด (Detail)</label>
                    <textarea 
                        rows={3}
                        value={formData.description}
                        onChange={e => setFormData({...formData, description: e.target.value})}
                        className="mt-1 block w-full rounded-md border-gray-300 shadow-sm focus:border-green-500 focus:ring-green-500 border p-2"
                    />
               </div>

               <div className="flex gap-3 pt-4">
                    <button 
                        type="button"
                        onClick={resetForm}
                        className="flex-1 bg-gray-200 text-gray-700 py-2 rounded-lg hover:bg-gray-300 transition-colors"
                        disabled={isLoading}
                    >
                        ยกเลิก
                    </button>
                    <button 
                        type="submit"
                        disabled={isLoading}
                        className="flex-1 bg-green-600 text-white py-2 rounded-lg hover:bg-green-700 transition-colors flex justify-center items-center gap-2"
                    >
                        {isLoading ? <Loader2 className="animate-spin" /> : <Save size={20} />}
                        บันทึกข้อมูล
                    </button>
               </div>
            </form>
          )}
        </div>
      </div>
    </div>
  );
};

export default ManageProducts;

import React, { useEffect, useState } from 'react';
import { signOut } from "firebase/auth";
import { auth } from "../firebaseConfig";
import { getProducts } from '../services/posService';
import { Product, CartItem, Category } from '../types';
import ProductCard from './ProductCard';
import ManageProducts from './ManageProducts';
import { LogOut, RefreshCcw, Coffee, Cake, IceCream, Utensils, X, Plus, Minus, Trash2, Pencil, AlertTriangle, Save, Settings } from 'lucide-react';

const POSLayout: React.FC = () => {
  const [products, setProducts] = useState<Product[]>([]);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [loading, setLoading] = useState(true);
  const [activeCategory, setActiveCategory] = useState<Category>('All');
  const [lightboxImg, setLightboxImg] = useState<string | null>(null);

  // State for Management
  const [isManageOpen, setIsManageOpen] = useState(false);

  // State for Delete Confirmation
  const [deleteId, setDeleteId] = useState<string | null>(null);

  // State for Edit Mode
  const [editingItem, setEditingItem] = useState<CartItem | null>(null);
  const [editQuantity, setEditQuantity] = useState<number | string>(1);

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    setLoading(true);
    try {
      const data = await getProducts();
      setProducts(data);
    } catch (error) {
      console.error("Failed to load products");
    } finally {
      setLoading(false);
    }
  };

  const handleLogout = () => {
    signOut(auth);
  };

  const addToCart = (product: Product) => {
    // Check if sold out
    if (product.status === 'Sold Out') {
        alert("สินค้านี้หมดชั่วคราว");
        return;
    }

    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        return prev.map(item => 
          item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item
        );
      }
      return [...prev, { ...product, quantity: 1 }];
    });
  };

  const updateQuantity = (productId: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === productId) {
        const newQty = item.quantity + delta;
        return newQty > 0 ? { ...item, quantity: newQty } : item;
      }
      return item;
    }));
  };

  const clearCart = () => setCart([]);

  // --- Delete Logic ---
  const confirmDelete = () => {
    if (deleteId) {
      setCart(prev => prev.filter(item => item.id !== deleteId));
      setDeleteId(null);
    }
  };

  // --- Edit Logic ---
  const handleEditClick = (item: CartItem) => {
    setEditingItem(item);
    setEditQuantity(item.quantity);
  };

  const handleSaveEdit = () => {
    if (editingItem) {
      const newQty = parseInt(String(editQuantity), 10);
      if (!isNaN(newQty) && newQty > 0) {
        setCart(prev => prev.map(item => 
            item.id === editingItem.id ? { ...item, quantity: newQty } : item
        ));
        setEditingItem(null);
      } else {
        alert("กรุณาระบุจำนวนให้ถูกต้อง (มากกว่า 0)");
      }
    }
  };

  const totalAmount = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);

  const filteredProducts = activeCategory === 'All' 
    ? products 
    : products.filter(p => p.category === activeCategory || (activeCategory === 'Coffee' && !p.category));

  const categories: {id: Category, label: string, icon: React.ReactNode}[] = [
    { id: 'All', label: 'ทั้งหมด', icon: <Utensils size={18} /> },
    { id: 'Coffee', label: 'กาแฟ', icon: <Coffee size={18} /> },
    { id: 'Bakery', label: 'เบเกอรี่', icon: <Cake size={18} /> },
    { id: 'Dessert', label: 'ของหวาน', icon: <IceCream size={18} /> },
  ];

  return (
    <div className="flex flex-col h-screen overflow-hidden bg-gray-50">
      {/* Header */}
      <header className="bg-white shadow-sm h-16 flex items-center justify-between px-6 z-20">
        <h1 className="text-xl font-bold text-gray-800 flex items-center gap-2">
           <Coffee className="text-green-600" />
           Cafe POS
        </h1>
        <div className="flex items-center gap-4">
            <button 
                onClick={() => setIsManageOpen(true)}
                className="flex items-center gap-2 bg-gray-100 hover:bg-green-100 text-gray-700 hover:text-green-700 px-4 py-2 rounded-full transition-colors text-sm font-medium"
            >
                <Settings size={18} />
                จัดการร้าน (Manage)
            </button>
            <div className="h-6 w-px bg-gray-300"></div>
            <button 
            onClick={handleLogout} 
            className="flex items-center gap-2 text-gray-600 hover:text-red-500 transition-colors"
            >
            <LogOut size={20} />
            <span>ออกจากระบบ</span>
            </button>
        </div>
      </header>

      {/* Main Content */}
      <div className="flex flex-1 overflow-hidden">
        {/* Left Side: Product Selection */}
        <div className="w-full md:w-2/3 lg:w-3/4 flex flex-col bg-gray-100 border-r border-gray-200">

          {/* Category Tabs */}
          <div className="p-4 bg-white shadow-sm overflow-x-auto whitespace-nowrap">
            <h2 className="text-lg font-bold mb-3 text-gray-700">โซนเลือกสินค้า</h2>
            <div className="flex space-x-2">
              {categories.map(cat => (
                <button
                  key={cat.id}
                  onClick={() => setActiveCategory(cat.id)}
                  className={`flex items-center gap-2 px-6 py-2.5 rounded-full text-sm font-medium transition-all duration-200 ${
                    activeCategory === cat.id 
                    ? 'bg-green-600 text-white shadow-md transform scale-105' 
                    : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
                  }`}
                >
                  {cat.icon}
                  {cat.label}
                </button>
              ))}
            </div>
          </div>

          {/* Product Grid */}
          <div className="flex-1 overflow-y-auto p-4 md:p-6">
            {loading ? (
              <div className="flex justify-center items-center h-full text-gray-400">
                <RefreshCcw className="animate-spin mr-2" /> Loading Products...
              </div>
            ) : (
              <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-4 md:gap-6">
                {filteredProducts.map(product => (
                  <ProductCard 
                    key={product.id} 
                    product={product} 
                    onClick={addToCart}
                    onImageClick={setLightboxImg}
                  />
                ))}
              </div>
            )}
          </div>
        </div>

        {/* Right Side: Cart & Checkout */}
        <div className="w-full md:w-1/3 lg:w-1/4 bg-white flex flex-col shadow-xl h-full z-10">
          <div className="p-4 bg-green-50 border-b border-green-100">
             <h2 className="text-xl font-bold text-gray-800">โซนจ่ายเงิน</h2>
          </div>

          {/* Cart Items List */}
          <div className="flex-1 overflow-y-auto p-4 space-y-3">
             {cart.length === 0 ? (
               <div className="h-full flex flex-col items-center justify-center text-gray-400 opacity-50">
                  <Utensils size={48} className="mb-2" />
                  <p>ยังไม่มีรายการสินค้า</p>
               </div>
             ) : (
               <table className="w-full text-sm">
                 <thead className="text-gray-500 border-b">
                   <tr>
                     <th className="text-left pb-2 font-normal">รายการ</th>
                     <th className="text-right pb-2 font-normal">ราคา</th>
                   </tr>
                 </thead>
                 <tbody className="divide-y">
                   {cart.map((item) => (
                     <tr key={item.id} className="group">
                       <td className="py-3 pr-2">
                         <div className="font-medium text-gray-800">{item.name}</div>
                         <div className="text-xs text-gray-400">{item.unit}</div>
                         <div className="flex items-center mt-1 space-x-2">
                            <button 
                                onClick={() => updateQuantity(item.id, -1)}
                                className="p-1 bg-gray-200 rounded hover:bg-gray-300 text-gray-600"
                            >
                                <Minus size={12} />
                            </button>
                            <span className="font-bold w-6 text-center">{item.quantity}</span>
                            <button 
                                onClick={() => updateQuantity(item.id, 1)}
                                className="p-1 bg-gray-200 rounded hover:bg-gray-300 text-gray-600"
                            >
                                <Plus size={12} />
                            </button>

                            {/* Edit Button */}
                            <button 
                                onClick={() => handleEditClick(item)}
                                className="ml-2 text-blue-400 hover:text-blue-600 p-1 opacity-0 group-hover:opacity-100 transition-opacity"
                                title="แก้ไข"
                            >
                                <Pencil size={14} />
                            </button>

                            {/* Delete Button */}
                            <button 
                              onClick={() => setDeleteId(item.id)}
                              className="text-red-400 hover:text-red-600 p-1 opacity-0 group-hover:opacity-100 transition-opacity"
                              title="ลบรายการ"
                            >
                              <Trash2 size={14} />
                            </button>
                         </div>
                       </td>
                       <td className="text-right align-top py-3 font-semibold text-gray-700">
                         {(item.price * item.quantity).toLocaleString()}
                       </td>
                     </tr>
                   ))}
                 </tbody>
               </table>
             )}
          </div>

          {/* Summary & Actions */}
          <div className="bg-gray-50 p-4 border-t border-gray-200 shadow-inner">
             <div className="flex justify-between items-end mb-4 border-b border-gray-200 pb-4">
                <span className="text-lg font-medium text-gray-600">ยอดรวมสุทธิ</span>
                <span className="text-3xl font-bold text-green-700">{totalAmount.toLocaleString(undefined, { minimumFractionDigits: 2 })}</span>
             </div>

             <div className="grid grid-cols-2 gap-3 mb-3">
                <button className="bg-yellow-400 hover:bg-yellow-500 text-yellow-900 font-semibold py-3 rounded-lg transition-colors">
                  พักบิล
                </button>
                <button 
                  onClick={clearCart}
                  className="bg-white border border-red-500 text-red-500 hover:bg-red-50 font-semibold py-3 rounded-lg transition-colors"
                >
                  ล้างตระกร้า
                </button>
             </div>
             <button className="w-full bg-green-700 hover:bg-green-800 text-white font-bold text-xl py-4 rounded-xl shadow-lg hover:shadow-green-500/30 transition-all transform active:scale-95">
               ชำระเงิน (Charge)
             </button>
          </div>
        </div>
      </div>

      {/* Manage Products Drawer */}
      <ManageProducts 
        isOpen={isManageOpen} 
        onClose={() => setIsManageOpen(false)} 
        products={products}
        onRefresh={fetchData}
      />

      {/* Lightbox Modal */}
      {lightboxImg && (
        <div 
          className="fixed inset-0 z-50 flex items-center justify-center bg-black bg-opacity-90 backdrop-blur-sm animate-fade-in"
          onClick={() => setLightboxImg(null)}
        >
            <button 
                className="absolute top-5 right-5 text-white hover:text-gray-300 transition-colors"
                onClick={() => setLightboxImg(null)}
            >
                <X size={40} />
            </button>
            <img 
                src={lightboxImg} 
                alt="Enlarged" 
                className="max-w-[90%] max-h-[90%] rounded-lg shadow-2xl transform transition-transform duration-300 scale-100"
                onClick={(e) => e.stopPropagation()} 
            />
        </div>
      )}

      {/* Delete Confirmation Modal */}
      {deleteId && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black bg-opacity-50 backdrop-blur-sm">
            <div className="bg-white rounded-lg shadow-xl p-6 w-full max-w-sm animate-scale-up">
                <div className="flex flex-col items-center text-center">
                    <div className="bg-red-100 p-3 rounded-full mb-4">
                        <AlertTriangle className="text-red-600 h-8 w-8" />
                    </div>
                    <h3 className="text-lg font-bold text-gray-900 mb-2">ยืนยันการลบสินค้า</h3>
                    <p className="text-sm text-gray-500 mb-6">คุณแน่ใจหรือไม่ที่จะลบสินค้ารายการนี้ออกจากตระกร้า?</p>
                    <div className="flex w-full gap-3">
                        <button 
                            onClick={() => setDeleteId(null)}
                            className="flex-1 px-4 py-2 bg-gray-100 text-gray-700 rounded-lg hover:bg-gray-200 transition-colors font-medium"
                        >
                            ยกเลิก
                        </button>
                        <button 
                            onClick={confirmDelete}
                            className="flex-1 px-4 py-2 bg-red-600 text-white rounded-lg hover:bg-red-700 transition-colors font-medium"
                        >
                            ยืนยันลบ
                        </button>
                    </div>
                </div>
            </div>
        </div>
      )}

      {/* Edit Item Modal */}
      {editingItem && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black bg-opacity-50 backdrop-blur-sm">
            <div className="bg-white rounded-lg shadow-xl p-6 w-full max-w-sm animate-scale-up">
                <div className="flex justify-between items-start mb-4">
                    <h3 className="text-lg font-bold text-gray-900">แก้ไขจำนวน</h3>
                    <button onClick={() => setEditingItem(null)} className="text-gray-400 hover:text-gray-600">
                        <X size={20} />
                    </button>
                </div>

                <div className="mb-6">
                    <label className="block text-sm font-medium text-gray-700 mb-2">
                        {editingItem.name}
                    </label>
                    <div className="flex items-center border border-gray-300 rounded-md overflow-hidden focus-within:ring-2 focus-within:ring-green-500 focus-within:border-green-500">
                        <input 
                            type="number" 
                            min="1"
                            value={editQuantity}
                            onChange={(e) => setEditQuantity(e.target.value)}
                            className="w-full p-3 text-center text-lg outline-none"
                            autoFocus
                        />
                    </div>
                    <p className="text-xs text-gray-500 mt-2 text-right">ราคาต่อชิ้น: {editingItem.price.toLocaleString()} บาท</p>
                </div>

                <button 
                    onClick={handleSaveEdit}
                    className="w-full flex items-center justify-center gap-2 px-4 py-3 bg-green-600 text-white rounded-lg hover:bg-green-700 transition-colors font-bold"
                >
                    <Save size={18} />
                    บันทึกการแก้ไข
                </button>
            </div>
        </div>
      )}

    </div>
  );
};

export default POSLayout;

import React from 'react';
import { Product } from '../types';

interface ProductCardProps {
  product: Product;
  onClick: (product: Product) => void;
  onImageClick: (imgUrl: string) => void;
}

const ProductCard: React.FC<ProductCardProps> = ({ product, onClick, onImageClick }) => {
  const isSoldOut = product.status === 'Sold Out';

  return (
    <div 
      className={`group bg-white rounded-xl shadow-md overflow-hidden transform transition duration-300 
        ${isSoldOut ? 'opacity-60 cursor-not-allowed' : 'hover:-translate-y-2 hover:shadow-2xl hover:border-green-200 cursor-pointer'} 
        border border-transparent h-full flex flex-col relative`}
      onClick={() => !isSoldOut && onClick(product)}
    >
      {isSoldOut && (
        <div className="absolute inset-0 z-20 flex items-center justify-center bg-black bg-opacity-20 pointer-events-none">
            <div className="bg-red-600 text-white px-4 py-1 rounded-full font-bold text-sm transform -rotate-12 shadow-lg">
                SOLD OUT
            </div>
        </div>
      )}

      <div className="relative overflow-hidden h-48">
        <img 
          src={product.imageUrl} 
          alt={product.name} 
          className={`w-full h-full object-cover transition-transform duration-500 ${!isSoldOut && 'group-hover:scale-110'}`}
          onClick={(e) => {
            e.stopPropagation();
            if(product.imageUrl) onImageClick(product.imageUrl);
          }}
        />
        {/* Tooltip implementation matching design */}
        {product.description && !isSoldOut && (
          <div className="absolute bottom-0 left-1/2 transform -translate-x-1/2 translate-y-full group-hover:-translate-y-12 transition-transform duration-300 z-10">
             <div className="bg-gray-800 text-white text-xs px-3 py-1 rounded shadow-lg whitespace-nowrap opacity-0 group-hover:opacity-100 transition-opacity delay-100">
                {product.description}
             </div>
          </div>
        )}
      </div>
      <div className="p-4 flex flex-col flex-grow justify-between text-center">
        <div>
            <h5 className="text-lg font-semibold text-gray-800 mb-1">{product.name}</h5>
            {product.unit && <p className="text-xs text-gray-500 mb-2">{product.unit}</p>}
        </div>
        <p className="text-xl font-bold text-green-700">{product.price.toLocaleString()} บาท</p>
      </div>
    </div>
  );
};

export default ProductCard;

